mapper.select:
SELECT p.id, p.name, p.address, p.latitude, p.longitude, p.operating_hours, p.ai_score, p.status, p.created_at, (SELECT photo_url FROM place_photos WHERE place_id = p.id LIMIT 1) AS photo_url, (SELECT COUNT(*) FROM place_reviews WHERE place_id = p.id) AS review_count, (SELECT COUNT(*) FROM place_bookmarks WHERE place_id = p.id) AS bookmark_count, (SELECT rest_type FROM place_tags WHERE place_id = p.id LIMIT 1) AS first_rest_type FROM places p
INNER JOIN place_tags pt ON p.id = pt.place_id AND pt.rest_type = #{restType}
WHERE p.status = 'approved'
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR p.address LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY p.ai_score DESC LIMIT #{size} OFFSET #{offset}

SELECT id, name, address, latitude, longitude, operating_hours, ai_score, status, created_at
FROM places
WHERE id = #{id}

SELECT id, place_id, tag_name, rest_type
FROM place_tags
WHERE place_id = #{placeId}

SELECT id, place_id, photo_url, source
FROM place_photos
WHERE place_id = #{placeId}

SELECT id, `쉼표번호`, place_id, created_at
FROM place_bookmarks
WHERE `쉼표번호` = #{쉼표번호} AND place_id = #{placeId}
